/**
 * Main App Component
 * Root component with authentication flow and dashboard
 */

import React, { useState, useEffect } from "react";
import axios from "axios";
import { AuthProvider, useAuth } from "./context/AuthContext";
import LoginPage from "./pages/LoginPage";
import RegisterPage from "./pages/RegisterPage";
import Dashboard from "./components/Dashboard";
import AddMedication from "./components/AddMedication";
import Header from "./components/Header";

// API Base URL
const API_URL = "http://localhost:5000/api";

/**
 * Main Application Content (with auth)
 */
function AppContent() {
  const { user, isAuthenticated, loading: authLoading, logout } = useAuth();

  // Auth page state (login or register)
  const [authPage, setAuthPage] = useState("login");

  // Medications state
  const [medications, setMedications] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [showAddForm, setShowAddForm] = useState(false);

  /**
   * Fetch all medications from the API
   */
  const fetchMedications = async () => {
    if (!isAuthenticated) return;

    try {
      setLoading(true);
      setError(null);

      const response = await axios.get(`${API_URL}/medications`);

      if (response.data.success) {
        setMedications(response.data.data);
      }
    } catch (err) {
      console.error("Error fetching medications:", err);
      if (err.response?.status === 401) {
        logout();
      } else {
        setError("Failed to fetch medications. Please try again.");
      }
    } finally {
      setLoading(false);
    }
  };

  /**
   * Add a new medication
   */
  const addMedication = async (medicationData) => {
    try {
      const response = await axios.post(
        `${API_URL}/medications`,
        medicationData,
      );

      if (response.data.success) {
        fetchMedications();
        setShowAddForm(false);
        return { success: true };
      }
    } catch (err) {
      console.error("Error adding medication:", err);
      return {
        success: false,
        message: err.response?.data?.message || "Failed to add medication",
      };
    }
  };

  /**
   * Delete a medication
   */
  const deleteMedication = async (id) => {
    try {
      await axios.delete(`${API_URL}/medications/${id}`);
      fetchMedications();
    } catch (err) {
      console.error("Error deleting medication:", err);
      setError("Failed to delete medication");
    }
  };

  /**
   * Refill a medication
   */
  const refillMedication = async (id, totalQuantity) => {
    try {
      await axios.put(`${API_URL}/medications/${id}/refill`, { totalQuantity });
      fetchMedications();
    } catch (err) {
      console.error("Error refilling medication:", err);
      setError("Failed to refill medication");
    }
  };

  /**
   * Take a dose of medication
   */
  const takeDose = async (id, pillCount = 1) => {
    try {
      await axios.put(`${API_URL}/medications/${id}/take-dose`, { pillCount });
      fetchMedications();
    } catch (err) {
      console.error("Error taking dose:", err);
      setError(err.response?.data?.message || "Failed to take dose");
    }
  };

  // Fetch medications when authenticated
  useEffect(() => {
    if (isAuthenticated) {
      fetchMedications();
    } else {
      setMedications([]);
      setLoading(false);
    }
  }, [isAuthenticated]);

  // Show loading screen during initial auth check
  if (authLoading) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-blue-50 via-white to-purple-50 flex items-center justify-center">
        <div className="text-center">
          <div className="inline-flex items-center justify-center w-16 h-16 bg-blue-600 rounded-2xl mb-4 animate-pulse">
            <svg
              className="w-10 h-10 text-white"
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M19.428 15.428a2 2 0 00-1.022-.547l-2.387-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z"
              />
            </svg>
          </div>
          <p className="text-gray-600 font-medium">Loading MedTracker...</p>
        </div>
      </div>
    );
  }

  // Show login/register pages if not authenticated
  if (!isAuthenticated) {
    if (authPage === "register") {
      return <RegisterPage onSwitchToLogin={() => setAuthPage("login")} />;
    }
    return <LoginPage onSwitchToRegister={() => setAuthPage("register")} />;
  }

  // Main dashboard view for authenticated users
  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 via-blue-50 to-indigo-50">
      {/* Header */}
      <Header
        user={user}
        onLogout={logout}
        onAddMedication={() => setShowAddForm(true)}
      />

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Error Banner */}
        {error && (
          <div className="mb-6 bg-red-50 border border-red-200 rounded-xl p-4 flex items-center justify-between">
            <div className="flex items-center">
              <svg
                className="w-5 h-5 text-red-500 mr-3"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"
                />
              </svg>
              <span className="text-red-700">{error}</span>
            </div>
            <button
              onClick={() => setError(null)}
              className="text-red-500 hover:text-red-700"
            >
              <svg
                className="w-5 h-5"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M6 18L18 6M6 6l12 12"
                />
              </svg>
            </button>
          </div>
        )}

        {/* Dashboard */}
        <Dashboard
          medications={medications}
          loading={loading}
          onDelete={deleteMedication}
          onRefill={refillMedication}
          onTakeDose={takeDose}
          onAddClick={() => setShowAddForm(true)}
        />
      </main>

      {/* Add Medication Modal */}
      {showAddForm && (
        <AddMedication
          onAdd={addMedication}
          onClose={() => setShowAddForm(false)}
        />
      )}

      {/* Footer */}
      <footer className="bg-white/50 backdrop-blur-sm border-t border-gray-200 mt-auto">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
          <div className="flex flex-col md:flex-row items-center justify-between">
            <p className="text-gray-500 text-sm">
              © 2026 MedTracker - College Project | MERN Stack Application
            </p>
            <div className="flex items-center space-x-4 mt-2 md:mt-0">
              <span className="text-xs text-gray-400">
                Built with ❤️ using React & Node.js
              </span>
            </div>
          </div>
        </div>
      </footer>
    </div>
  );
}

/**
 * App wrapper with AuthProvider
 */
function App() {
  return (
    <AuthProvider>
      <AppContent />
    </AuthProvider>
  );
}

export default App;
